        let a = args(&["--bogus"]);
        let result = parse_args(&mut a.into_iter());
        assert!(result.is_err());
        assert!(result.unwrap_err().contains("unknown finalize option"));
    }

    #[test]
    fn build_exec_args_roundtrip() {
        let opts = FinalizeOpts {
